import os
import logging
import psutil

# Set up logging
logging.basicConfig(filename='file_mover.log', level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

def is_file_in_use(file_path):
    """Check if a file is currently in use by any process."""
    for proc in psutil.process_iter(['pid', 'name']):
        try:
            if proc.info['name'] == os.path.basename(file_path):
                return True
        except (psutil.NoSuchProcess, psutil.AccessDenied, psutil.ZombieProcess):
            pass
    return False

def move_file_to_archive(file_path):
    """Move a file to the archive directory."""
    try:
        os.rename(file_path, f'archive/{os.path.basename(file_path)}')
        logging.info(f'Moved file {file_path} to archive directory.')
    except Exception as e:
        logging.error(f'Failed to move file {file_path}: {e}')

def main(file_list):
    """Move files to the archive directory."""
    for file_path in file_list:
        if not is_file_in_use(file_path):
            move_file_to_archive(file_path)

if __name__ == '__main__':
    # Example usage
    file_list = ['path/to/file1.txt', 'path/to/file2.txt', 'path/to/file3.txt']
    main(file_list)
